const shortening={isgd:async function(t){const n="https://is.gd/create.php",o={method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({format:"json",url:t.trim()})},e=await fetch(n,o),a=await e.json();return a.shorturl},vgd:async function(t){const n="https://v.gd/create.php",o={method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({format:"json",url:t.trim()})},e=await fetch(n,o),a=await e.json();return a.shorturl},spoome:async function(t){const n="https://spoo.me/",o={method:"POST",headers:{Accept:"application/json","Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({url:t.trim()})},e=await fetch(n,o),a=await e.json();return a.short_url},trimmlink:async function(t){const n="https://trimm.link/",o={method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({link:t.trim()})},e=await fetch(n+"shorten",o),a=await e.json(),r=n+(a.word||"");return r}};